import React, { useState, useContext } from 'react';
import { Link } from 'react-router-dom';
import { FaComment, FaThumbsUp, FaRegThumbsUp, FaUser, FaClock } from 'react-icons/fa';
import { AuthContext } from '../context/AuthContext';
import formatDate from '../utils/formatDate';
import forumService from '../services/forumService';
import { toast } from 'react-toastify';

const ForumPostCard = ({ post, refreshPosts }) => {
  const { user } = useContext(AuthContext);
  const [likeLoading, setLikeLoading] = useState(false);
  
  // Check if user has already liked the post
  const hasLiked = user && post.likes.includes(user._id);
  
  const handleLike = async () => {
    if (!user) {
      toast.error('Please log in to like posts');
      return;
    }
    
    try {
      setLikeLoading(true);
      await forumService.likePost(post._id);
      if (refreshPosts) refreshPosts();
    } catch (error) {
      toast.error('Failed to like post');
      console.error('Like error:', error);
    } finally {
      setLikeLoading(false);
    }
  };
  
  const truncateText = (text, maxLength = 150) => {
    if (!text || text.length <= maxLength) return text;
    return text.substr(0, maxLength) + '...';
  };

  return (
    <div className="bg-white dark:bg-gray-800 rounded-lg shadow-md p-4 mb-4 hover:shadow-lg transition-shadow">
      <div className="flex justify-between items-start mb-3">
        <div className="flex items-center">
          <div className="bg-green-100 dark:bg-green-900 p-2 rounded-full mr-3">
            <FaUser className="text-green-600 dark:text-green-400" />
          </div>
          <div>
            <h3 className="font-semibold text-gray-800 dark:text-white">{post.author?.name || 'Anonymous'}</h3>
            <div className="flex items-center text-xs text-gray-500 dark:text-gray-400">
              <FaClock className="mr-1" />
              <span>{formatDate(post.createdAt)}</span>
            </div>
          </div>
        </div>
        <div className="px-2 py-1 bg-green-100 dark:bg-green-900 rounded text-xs text-green-800 dark:text-green-400">
          {post.category || 'General'}
        </div>
      </div>
      
      <Link to={`/forum/${post._id}`} className="block">
        <h2 className="text-xl font-bold text-gray-900 dark:text-white mb-2 hover:text-green-600 dark:hover:text-green-400">
          {post.title}
        </h2>
        <p className="text-gray-700 dark:text-gray-300 mb-4">
          {truncateText(post.description)}
        </p>
      </Link>
      
      <div className="flex justify-between items-center pt-3 border-t border-gray-200 dark:border-gray-700">
        <button 
          onClick={handleLike}
          disabled={likeLoading}
          className={`flex items-center ${hasLiked ? 'text-green-600 dark:text-green-400' : 'text-gray-500 dark:text-gray-400'} hover:text-green-600 dark:hover:text-green-400 disabled:opacity-50`}
        >
          {hasLiked ? <FaThumbsUp className="mr-1" /> : <FaRegThumbsUp className="mr-1" />}
          <span>{post.likes?.length || 0}</span>
        </button>
        
        <Link to={`/forum/${post._id}`} className="flex items-center text-gray-500 dark:text-gray-400 hover:text-green-600 dark:hover:text-green-400">
          <FaComment className="mr-1" />
          <span>{post.comments?.length || 0}</span>
        </Link>
      </div>
    </div>
  );
};

export default ForumPostCard;
